const rows = $input.all();
if (rows.length === 0 || !rows[0].json.subreddit_name) {
  return [{ json: { text: "No monitored subreddits or posts found.", post_ids: [], posts_refs: {} } }];
}

const subreddits = {};
const postIds = new Set();

rows.forEach(row => {
  const data = row.json;
  const subName = data.subreddit_name;

  if (!subreddits[subName]) {
    subreddits[subName] = {
      active: data.subreddit_active,
      posts: {}
    };
  }

  if (data.post_id) {
    postIds.add(data.post_id);
    if (!subreddits[subName].posts[data.post_id]) {
      subreddits[subName].posts[data.post_id] = {
        title: data.post_title,
        content: data.post_content,
        author: data.post_author,
        url: data.post_url,
        created_at: data.post_created_at,
        comments: []
      };
    }

    if (data.comment_id) {
      subreddits[subName].posts[data.post_id].comments.push({
        author: data.comment_author,
        content: data.comment_content,
        created_at: data.comment_created_at
      });
    }
  }
});

// Build plain-text prompt content for the LLM
let text = "Here is the Reddit monitoring data:\n\n";
text += "=== Monitored Subreddits ===\n";
for (const [subName, subInfo] of Object.entries(subreddits)) {
  text += `- r/${subName} (Status: ${subInfo.active ? 'Active' : 'Inactive'})\n`;
}
text += "\n=== New Posts & Comments (last 24h) ===\n\n";

// Build posts_refs for guaranteed programmatic links later
// Structure: { subredditName: [ { title, url, author } ] }
const postsRefs = {};

for (const [subName, subInfo] of Object.entries(subreddits)) {
  const postsList = Object.values(subInfo.posts);
  if (postsList.length === 0) continue;

  postsRefs[subName] = [];

  text += `Subreddit: r/${subName}\n`;
  postsList.forEach((post, index) => {
    text += `  Post #${index + 1}: ${post.title || 'No Title'}\n`;
    text += `  Author: u/${post.author || 'unknown'}\n`;
    text += `  Content: ${(post.content || '').substring(0, 500)}\n`;
    if (post.comments.length > 0) {
      text += `  Comments:\n`;
      post.comments.slice(0, 5).forEach((comment) => {
        text += `    - [u/${comment.author || 'unknown'}]: ${(comment.content || '').substring(0, 300)}\n`;
      });
    }
    text += `  -------------------------------------------\n`;

    if (post.url) {
      postsRefs[subName].push({ title: post.title || 'Post', url: post.url, author: post.author || 'unknown' });
    }
  });
}

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/bella.md', 'utf8');
} catch (e) {
  persona = 'Warm, charming Italian secretary named Bella.';
}

return [{ json: { text: text, post_ids: Array.from(postIds), posts_refs: postsRefs, bella_persona: persona } }];

const response = $input.first().json.response || '';
let clean = response.replace(/\*\*(.*?)\*\*/g, '*$1*');
clean = clean.replace(/#{1,6}\s+(.*?)($|\n)/g, '*$1*\n');
clean = clean.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<$2|$1>');
return [{ json: { response: clean } }];

// Pull the LLM summary from the previous node
const summary = $('Convert Markdown to Slack').first().json.response || '';

// Pull the posts_refs that were built deterministically in Format Posts for LLM
const postsRefs = $('Format Posts for LLM').first().json.posts_refs || {};

// Build a guaranteed References section
let refs = '';
const subreddits = Object.keys(postsRefs);
if (subreddits.length > 0) {
  refs += '\n\n📎 *References*\n';
  for (const subName of subreddits) {
    const posts = postsRefs[subName];
    if (!posts || posts.length === 0) continue;
    refs += `*r/${subName}*\n`;
    posts.forEach(post => {
      refs += `• <${post.url}|${post.title}>\n`;
    });
  }
}

return [{ json: { final_message: summary + refs } }];
